query:
UPDATE competition_participants cp SET 
  salesCount = (SELECT COUNT(*) FROM sales WHERE sellerId = cp.sellerId AND competitionId = cp.competitionId AND status = 'approved'),
  points = (SELECT COALESCE(SUM(points), 0) FROM sales WHERE sellerId = cp.sellerId AND competitionId = cp.competitionId AND status = 'approved');

